using ContosoUniversity.Services;
using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain the static queue to prevent test interference
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "101", null, EntityOperation.UPDATE, "Teacher");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
            Assert.AreEqual("Teacher", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _sut.SendNotification("Department", "5", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'Test' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'Test' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'Test' has been deleted")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessages(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "1", "Test", operation, "User");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.AreEqual(expectedMessage, notification.Message);
            Assert.AreEqual(operation.ToString(), notification.Operation);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.IsTrue(first.Message.Contains("First"));
            var second = _sut.ReceiveNotification();
            Assert.IsTrue(second.Message.Contains("Second"));
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsTrue(notification.CreatedAt >= before);
            Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op but should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
            _sut.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            var service = new NotificationService();
            service.Dispose();
            service.Dispose(); // Double dispose should be safe
        }

        [TestMethod]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            // Act
            _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
        }
    }
}

