            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Courses.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            TestHelpers.SeedDepartments(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2000, Credits = 4, DepartmentID = 1 };

            // Act
