using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateOptions()));
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            // Arrange
            TestHelpers.SeedInstructors(_context);

            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Arrange
            SeedInstructorsWithCourses();

            // Act
            var result = _controller.Index(10, null) as ViewResult;

            // Assert
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            TestHelpers.SeedInstructors(_context);

            // Act
            var result = _controller.Details(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Zheng", model.LastName);
        }

        [TestMethod]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructorAndCourses()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_Post_ValidInstructorWithoutCourses_RedirectsToIndex()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15)
            };

            // Act
            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            // Arrange
            TestHelpers.SeedCourses(_context);
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15)
            };
            var selectedCourses = new[] { "1050", "4022" };

            // Act
            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var saved = _context.Instructors.Include(i => i.CourseAssignments).First(i => i.LastName == "WithCourses");
            Assert.AreEqual(2, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            // Arrange
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _controller.Create(instructor, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            SeedInstructorsWithCourses();

            // Act
            var result = _controller.Edit((int?)10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Zheng", model.LastName);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            TestHelpers.SeedInstructors(_context);

            // Act
            var result = _controller.Delete(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Zheng", model.LastName);
        }

        [TestMethod]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Arrange
            SeedInstructorsWithOfficeAssignment();

            // Act
            var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsNull(_context.Instructors.Find(10));
        }

        [TestMethod]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Arrange
            SeedInstructorsWithOfficeAssignment();
            _context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Today,
                InstructorID = 10
            });
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(10);

            // Assert
            var dept = _context.Departments.Find(1);
            Assert.IsNull(dept.InstructorID);
        }

        private void SeedInstructorsWithCourses()
        {
            TestHelpers.SeedCourses(_context);
            var instructor = new Instructor
            {
                ID = 10,
                LastName = "Zheng",
                FirstMidName = "Roger",
                HireDate = new DateTime(2004, 2, 12),
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1050, InstructorID = 10 }
                }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
        }

        private void SeedInstructorsWithOfficeAssignment()
        {
            var instructor = new Instructor
            {
                ID = 10,
                LastName = "Zheng",
                FirstMidName = "Roger",
                HireDate = new DateTime(2004, 2, 12),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { InstructorID = 10, Location = "Room 101" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
        }
    }
}

