using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new HomeController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateOptions()));
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { ID = 1, LastName = "A", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "C", FirstMidName = "D", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 3, LastName = "E", FirstMidName = "F", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count); // Two distinct enrollment dates
            var group2020 = model.First(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
            Assert.AreEqual(2, group2020.StudentCount);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            // Act
            var result = _controller.Error() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessageAndReturnsView()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

