using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class ModelTests
    {
        [TestMethod]
        [DataRow("Smith", "John", "Smith, John")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary")]
        [DataRow("", "Test", ", Test")]
        public void Person_FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Act & Assert
            Assert.AreEqual(expected, student.FullName);
        }

        [TestMethod]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            // Arrange
            var instructor = new Instructor { LastName = "Zheng", FirstMidName = "Roger" };

            // Act & Assert
            Assert.AreEqual("Zheng, Roger", instructor.FullName);
        }

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_TrueWhenRequestIdSet()
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = "abc123" };

            // Assert
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        [DataRow(null)]
        [DataRow("")]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty(string requestId)
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = requestId };

            // Assert
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void Notification_Properties_SetCorrectly()
        {
            // Arrange
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "5",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            // Assert
            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("5", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/Uploads/test.jpg"
            };

            // Assert
            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/Uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            // Arrange
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 5
            };

            // Assert
            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Mathematics", dept.Name);
            Assert.AreEqual(100000m, dept.Budget);
            Assert.AreEqual(new DateTime(2020, 1, 1), dept.StartDate);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Enrollment_GradeCanBeNull()
        {
            // Arrange
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = null
            };

            // Assert
            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A)]
        [DataRow(Grade.B)]
        [DataRow(Grade.C)]
        [DataRow(Grade.D)]
        [DataRow(Grade.F)]
        public void Enrollment_AllGradeValuesValid(Grade grade)
        {
            // Arrange
            var enrollment = new Enrollment { Grade = grade };

            // Assert
            Assert.AreEqual(grade, enrollment.Grade);
        }

        [TestMethod]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            // Arrange
            var assignment = new CourseAssignment
            {
                InstructorID = 10,
                CourseID = 1050
            };

            // Assert
            Assert.AreEqual(10, assignment.InstructorID);
            Assert.AreEqual(1050, assignment.CourseID);
        }

        [TestMethod]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            // Arrange
            var office = new OfficeAssignment
            {
                InstructorID = 10,
                Location = "Smith 17"
            };

            // Assert
            Assert.AreEqual(10, office.InstructorID);
            Assert.AreEqual("Smith 17", office.Location);
        }
    }
}

