using ContosoUniversity.Data;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelper
{
    public static SchoolContext CreateInMemoryContext(string? databaseName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains the static notification queue to prevent test interference.
    /// Must be called before/after tests that use NotificationService or any controller.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    /// <summary>
    /// Helper to read a property from an anonymous type (e.g., JsonResult.Value).
    /// </summary>
    public static T GetAnonymousProperty<T>(object obj, string propertyName)
    {
        var prop = obj.GetType().GetProperty(propertyName);
        if (prop == null)
            throw new InvalidOperationException($"Property '{propertyName}' not found on type '{obj.GetType().Name}'");
        return (T)prop.GetValue(obj)!;
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _sut = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    // --- SendNotification tests ---

    [TestMethod]
    public void SendNotification_WithEntityTypeAndId_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesDisplayNameInMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Doe"),
            $"Expected message to contain 'John Doe' but was '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"),
            $"Expected message to contain 'ID: 42' but was '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_MessageContainsNew()
    {
        // Act
        _sut.SendNotification("Course", "101", "Math 101", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.StartsWith("New "),
            $"Expected message to start with 'New ' but was '{notification.Message}'");
    }

    [TestMethod]
    [DataRow("CREATE", "has been created", DisplayName = "CREATE operation")]
    [DataRow("UPDATE", "has been updated", DisplayName = "UPDATE operation")]
    [DataRow("DELETE", "has been deleted", DisplayName = "DELETE operation")]
    public void SendNotification_VariousOperations_GeneratesCorrectMessage(string operationStr, string expectedPhrase)
    {
        // Arrange
        var operation = Enum.Parse<EntityOperation>(operationStr);

        // Act
        _sut.SendNotification("Student", "1", "Test Student", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedPhrase),
            $"Expected message to contain '{expectedPhrase}' but was '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToNow()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now.AddSeconds(1);
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void SendNotification_FiveParamOverload_WithUserName_SetsAllFields()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "testuser");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("testuser", notification.CreatedBy);
        Assert.IsTrue(notification.Message.Contains("Engineering"));
    }

    [TestMethod]
    public void SendNotification_FourParamOverload_WithUserName_SetsCreatedBy()
    {
        // Act (4-param overload: entityType, entityId, operation, userName)
        _sut.SendNotification("Student", "7", EntityOperation.UPDATE, "editor");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("editor", notification.CreatedBy);
        Assert.IsTrue(notification.Message.Contains("ID: 7"));
    }

    // --- ReceiveNotification tests ---

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_Dequeues_SecondCallReturnsNull()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsInFifoOrder()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.AreEqual("Student", first.EntityType);
        Assert.IsNotNull(second);
        Assert.AreEqual("Course", second.EntityType);
        Assert.IsNotNull(third);
        Assert.AreEqual("Department", third.EntityType);
    }

    // --- Queue cap enforcement ---

    [TestMethod]
    public void SendNotification_ExceedingMaxQueue_TrimsToMaxLength()
    {
        // Arrange & Act: Send 510 notifications (exceeds _maxQueueLength of 500)
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Assert: Count remaining notifications
        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }
        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count} items");
    }

    // --- MarkAsRead tests ---

    [TestMethod]
    public void MarkAsRead_WithAnyId_DoesNotThrow()
    {
        // MarkAsRead is a no-op but should never throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
        _sut.MarkAsRead(int.MaxValue);
    }

    // --- Dispose tests ---

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert: Dispose should not throw
        service.Dispose();
    }

    [TestMethod]
    public void Dispose_CalledMultipleTimes_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert
        service.Dispose();
        service.Dispose();
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    // --- Constructor tests ---

    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a" }, 10, 3, 5);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages()
    {
        // Arrange & Act (10 items, 5 per page = 2 total pages)
        var list = new PaginatedList<string>(new List<string> { "a" }, 10, 1, 5);

        // Assert
        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_TotalPagesRoundsUp()
    {
        // Arrange & Act (11 items, 5 per page = ceil(2.2) = 3 total pages)
        var list = new PaginatedList<string>(new List<string> { "a" }, 11, 1, 5);

        // Assert
        Assert.AreEqual(3, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        CollectionAssert.AreEqual(items, list);
    }

    [TestMethod]
    public void Constructor_ZeroCount_ZeroTotalPages()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        // Assert
        Assert.AreEqual(0, list.TotalPages);
        Assert.AreEqual(0, list.Count);
    }

    // --- HasPreviousPage tests ---

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ThirdPage_ReturnsTrue()
    {
        var list = new PaginatedList<string>(new List<string>(), 30, 3, 10);
        Assert.IsTrue(list.HasPreviousPage);
    }

    // --- HasNextPage tests ---

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, 5 per page = 2 pages. Page 2 is the last.
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, 5 per page = 2 pages. Page 1 is not the last.
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, 5 per page = 1 page. Page 1 is the only page.
        var list = new PaginatedList<string>(new List<string>(), 3, 1, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_EmptyList_ReturnsFalse()
    {
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
        Assert.IsFalse(list.HasNextPage);
    }

    // --- Create (static factory method) tests ---

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_SinglePage_ReturnsAllItems()
    {
