using ContosoUniversity.Data;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelper
{
    public static SchoolContext CreateInMemoryContext(string? databaseName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains the static notification queue to prevent test interference.
    /// Must be called before/after tests that use NotificationService or any controller.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    /// <summary>
    /// Helper to read a property from an anonymous type (e.g., JsonResult.Value).
    /// </summary>
    public static T GetAnonymousProperty<T>(object obj, string propertyName)
    {
        var prop = obj.GetType().GetProperty(propertyName);
        if (prop == null)
            throw new InvalidOperationException($"Property '{propertyName}' not found on type '{obj.GetType().Name}'");
        return (T)prop.GetValue(obj)!;
    }
}

