    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsInFifoOrder()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act
