        var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        // Assert
        Assert.AreEqual(0, list.TotalPages);
        Assert.AreEqual(0, list.Count);
    }

    // --- HasPreviousPage tests ---

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ThirdPage_ReturnsTrue()
    {
        var list = new PaginatedList<string>(new List<string>(), 30, 3, 10);
        Assert.IsTrue(list.HasPreviousPage);
    }

    // --- HasNextPage tests ---

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, 5 per page = 2 pages. Page 2 is the last.
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, 5 per page = 2 pages. Page 1 is not the last.
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, 5 per page = 1 page. Page 1 is the only page.
        var list = new PaginatedList<string>(new List<string>(), 3, 1, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_EmptyList_ReturnsFalse()
    {
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
        Assert.IsFalse(list.HasNextPage);
    }

    // --- Create (static factory method) tests ---

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_SinglePage_ReturnsAllItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPageOfMultiple_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
        Assert.AreEqual(3, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    [DataRow(1, 10, 1, DisplayName = "1 item, 10 per page = 1 page")]
    [DataRow(5, 10, 1, DisplayName = "5 items, 10 per page = 1 page")]
    [DataRow(10, 10, 1, DisplayName = "10 items, 10 per page = 1 page")]
    [DataRow(11, 10, 2, DisplayName = "11 items, 10 per page = 2 pages")]
    [DataRow(20, 10, 2, DisplayName = "20 items, 10 per page = 2 pages")]
    [DataRow(21, 10, 3, DisplayName = "21 items, 10 per page = 3 pages")]
    [DataRow(100, 10, 10, DisplayName = "100 items, 10 per page = 10 pages")]
    public void Create_VariousCounts_CalculatesCorrectTotalPages(int itemCount, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var source = Enumerable.Range(1, itemCount).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void Create_PageSizeOne_CorrectPagination()
    {
        // Arrange
        var source = Enumerable.Range(1, 3).AsQueryable();

        // Act
        var page1 = PaginatedList<int>.Create(source, 1, 1);
        var page2 = PaginatedList<int>.Create(source, 2, 1);
        var page3 = PaginatedList<int>.Create(source, 3, 1);

        // Assert
        Assert.AreEqual(1, page1.Count);
        Assert.AreEqual(1, page1[0]);
        Assert.AreEqual(3, page1.TotalPages);

        Assert.AreEqual(1, page2.Count);
        Assert.AreEqual(2, page2[0]);

        Assert.AreEqual(1, page3.Count);
        Assert.AreEqual(3, page3[0]);
        Assert.IsFalse(page3.HasNextPage);
    }
}

