using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    private void EnqueueNotifications(int count)
    {
        using var ns = new NotificationService();
        for (int i = 0; i < count; i++)
        {
            ns.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE, "test");
        }
    }

    // ==================== GetNotifications tests ====================

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result.Value, "success"));
        Assert.AreEqual(0, TestHelper.GetAnonymousProperty<int>(result.Value, "count"));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange
        EnqueueNotifications(3);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result.Value, "success"));
        Assert.AreEqual(3, TestHelper.GetAnonymousProperty<int>(result.Value, "count"));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange
        EnqueueNotifications(15);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        Assert.AreEqual(10, TestHelper.GetAnonymousProperty<int>(result.Value, "count"));
    }

    [TestMethod]
    public void GetNotifications_DequeuedNotificationsAreNotReturnedAgain()
    {
        // Arrange
        EnqueueNotifications(3);

        // Act: first call dequeues all 3
        var result1 = _controller.GetNotifications();
        // Second call should get 0
        var result2 = _controller.GetNotifications();

        // Assert
        Assert.AreEqual(3, TestHelper.GetAnonymousProperty<int>(result1.Value!, "count"));
        Assert.AreEqual(0, TestHelper.GetAnonymousProperty<int>(result2.Value!, "count"));
    }

    [TestMethod]
    public void GetNotifications_ReturnsNotificationDetails()
    {
        // Arrange
        EnqueueNotifications(1);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        var notifications = TestHelper.GetAnonymousProperty<List<Notification>>(result.Value, "notifications");
        Assert.AreEqual(1, notifications.Count);
        Assert.AreEqual("Student", notifications[0].EntityType);
        Assert.AreEqual("0", notifications[0].EntityId);
    }

    // ==================== MarkAsRead tests ====================

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result.Value, "success"));
    }

    [TestMethod]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        // MarkAsRead is a no-op, so any id should succeed
        var result1 = _controller.MarkAsRead(0);
        var result2 = _controller.MarkAsRead(999);
        var result3 = _controller.MarkAsRead(-1);

        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result1.Value!, "success"));
        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result2.Value!, "success"));
        Assert.IsTrue(TestHelper.GetAnonymousProperty<bool>(result3.Value!, "success"));
    }

    // ==================== Index tests ====================

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }
}

