[TestMethod]
public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
{
    // Arrange - drain queue immediately before acting
    var service = new ContosoUniversity.Services.NotificationService();
    while (service.ReceiveNotification() != null) { }

    // Act
    _controller.TestSendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

    // Assert - find our notification (other tests may also enqueue)
    Notification notification = null;
    Notification item;
    while ((item = service.ReceiveNotification()) != null)
    {
        if (item.EntityType == "Student" && item.Message.Contains("John Doe"))
        {
            notification = item;
            break;
        }
    }
    if (notification == null)
    {
        // Might have been the first item before the loop
        Assert.Fail("Expected notification not found in queue");
    }
    Assert.AreEqual("Student", notification.EntityType);
    Assert.IsTrue(notification.Message.Contains("John Doe"));
}

