public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
{
    // Arrange - use unique marker to identify our notification
    var uniqueId = Guid.NewGuid().ToString();
    var service = new ContosoUniversity.Services.NotificationService();

    // Act
    _controller.TestSendNotification("Student", uniqueId, "John Doe", EntityOperation.CREATE);

    // Assert - drain until we find our notification
    Notification notification = null;
    Notification item;
    int maxAttempts = 1000;
    while (maxAttempts-- > 0 && (item = service.ReceiveNotification()) != null)
    {
        if (item.EntityId == uniqueId)
        {
            notification = item;
            break;
        }
    }
    Assert.IsNotNull(notification, "Expected notification not found in queue");
    Assert.AreEqual("Student", notification.EntityType);
    Assert.IsTrue(notification.Message.Contains("John Doe"));
}

