        public void GetNotifications_EmptyQueue_ReturnsCountZero()
        {
            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
            var count = result.Value.GetType().GetProperty("count")?.GetValue(result.Value);
            Assert.AreEqual(0, count);
            var success = result.Value.GetType().GetProperty("success")?.GetValue(result.Value);
            Assert.AreEqual(true, success);
        }

        [TestMethod]
        public void GetNotifications_DequeuedNotificationsNotReturnedAgain()
        {
            // Arrange - add 3 notifications
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);
            service.SendNotification("Student", "2", EntityOperation.CREATE);
            service.SendNotification("Student", "3", EntityOperation.CREATE);

            // Act: first call dequeues all 3
            var result1 = _controller.GetNotifications() as JsonResult;
            // Second call should get 0
            var result2 = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result1?.Value);
            Assert.IsNotNull(result2?.Value);
            var count1 = result1.Value.GetType().GetProperty("count")?.GetValue(result1.Value);
            var count2 = result2.Value.GetType().GetProperty("count")?.GetValue(result2.Value);
            Assert.AreEqual(3, count1);
            Assert.AreEqual(0, count2);
        }

