        public void TotalPages_CalculatedCorrectly_WithExactDivision()
        {
            // Arrange - 20 items, page size 10 = exactly 2 pages
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(2, result.TotalPages);
        }

        [TestMethod]
        [DataRow(1, 10, 1, DisplayName = "1 item = 1 page")]
        [DataRow(10, 10, 1, DisplayName = "10 items = 1 page")]
        [DataRow(11, 10, 2, DisplayName = "11 items = 2 pages")]
        [DataRow(20, 10, 2, DisplayName = "20 items = 2 pages")]
        [DataRow(21, 10, 3, DisplayName = "21 items = 3 pages")]
        [DataRow(100, 10, 10, DisplayName = "100 items = 10 pages")]
        public void Create_VariousCounts_CalculatesCorrectTotalPages(int itemCount, int pageSize, int expectedTotalPages)
        {
            // Arrange
            var source = Enumerable.Range(1, itemCount).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, result.TotalPages);
        }

        [TestMethod]
        public void Create_PageSizeOne_CorrectPagination()
        {
            // Arrange
            var source = Enumerable.Range(1, 3).AsQueryable();

            // Act
            var page1 = PaginatedList<int>.Create(source, 1, 1);
            var page2 = PaginatedList<int>.Create(source, 2, 1);
            var page3 = PaginatedList<int>.Create(source, 3, 1);

            // Assert
            Assert.AreEqual(1, page1.Count);
            Assert.AreEqual(1, page1[0]);
            Assert.AreEqual(3, page1.TotalPages);

            Assert.AreEqual(1, page2.Count);
            Assert.AreEqual(2, page2[0]);

            Assert.AreEqual(1, page3.Count);
            Assert.AreEqual(3, page3[0]);
            Assert.IsFalse(page3.HasNextPage);
        }

        [TestMethod]
        public void Constructor_AddsItemsToCollection()
        {
            // Arrange
            var items = new List<string> { "x", "y", "z" };

            // Act
            var list = new PaginatedList<string>(items, 3, 1, 10);

            // Assert
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        public void Constructor_ZeroCount_ZeroTotalPages()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

            // Assert
            Assert.AreEqual(0, list.TotalPages);
            Assert.IsFalse(list.HasPreviousPage);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_EmptyList_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void TotalPages_RoundsUpForPartialPage()
        {
            // Arrange - 11 items, page size 5 = ceil(2.2) = 3 pages
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);

            // Assert
            Assert.AreEqual(3, list.TotalPages);
        }
    }
}

